1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function typePremium(type: string, count: number): number {
18	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
19	    return BLOCK_PREMIUM;
20	  }
21	  return count * (BASE_PREMIUMS[type] ?? 0);
22	}
23	
24	function countByType(items: Array<{ type: string }>): Record<string, number> {
25	  const counts: Record<string, number> = {};
26	  for (const item of items) {
27	    counts[item.type] = (counts[item.type] ?? 0) + 1;
28	  }
29	  return counts;
30	}
31	
32	const CURSED_SURCHARGE_RATE = 0.5;
33	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	const LOYALTY_DISCOUNT_RATE = 0.2;
36	const LOYALTY_THRESHOLD = 2;
37	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
38	
39	function surchargeTotal<T extends { type: string }>(
40	  items: T[],
41	  appliesTo: (item: T) => boolean,
42	  rate: number,
43	): number {
44	  let total = 0;
45	  for (const item of items) {
46	    if (appliesTo(item)) {
47	      total += (BASE_PREMIUMS[item.type] ?? 0) * rate;
48	    }
49	  }
50	  return total;
51	}
52	
53	function cursedSurchargeTotal(items: Array<{ type: string; cursed?: boolean }>): number {
54	  return surchargeTotal(items, (item) => !!item.cursed, CURSED_SURCHARGE_RATE);
55	}
56	
57	function highEnchantmentSurchargeTotal(items: Array<{ type: string; enchantment?: number }>): number {
58	  return surchargeTotal(
59	    items,
60	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
61	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
62	  );
63	}
64	
65	function basePremiumTotal(items: Array<{ type: string }>): number {
66	  const countsByType = countByType(items);
67	  let total = 0;
68	  for (const [type, count] of Object.entries(countsByType)) {
69	    total += typePremium(type, count);
70	  }
71	  return total;
72	}
73	
74	function calculateQuotePremium(items: Array<{ type: string; cursed?: boolean; enchantment?: number }>, yearsWithMHPCO: number, quoteIndex: number): number {
75	  const policyBasePremium = basePremiumTotal(items);
76	  const itemAdjustedTotal = policyBasePremium + cursedSurchargeTotal(items) + highEnchantmentSurchargeTotal(items);
77	
78	  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBasePremium * LOYALTY_DISCOUNT_RATE : 0;
79	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
80	  const followUpDiscount = quoteIndex > 0 ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
81	  const rawPremium = itemAdjustedTotal - loyaltyDiscount + firstInsuranceSurcharge - followUpDiscount + PROCESSING_FEE;
82	  return Math.ceil(rawPremium);
83	}
84	
85	const INSURANCE_VALUES: Record<string, number> = {
86	  sword: 1000,
87	  rune: 250,
88	};
89	
90	const DEDUCTIBLE = 100;
91	const CAP_MULTIPLIER = 2;
92	
93	interface QuoteResult {
94	  premium: number;
95	}
96	
97	interface ClaimResult {
98	  payout: number;
99	  remainingCap: number;
100	}
101	
102	interface ScenarioOutcome {
103	  results: Array<QuoteResult | ClaimResult>;
104	}
105	
106	function calculateClaimResult(
107	  policy: { items: Array<{ type: string }> },
108	  damages: Array<{ type: string; amount: number }>,
109	): ClaimResult {
110	  const insuranceSum = policy.items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
111	  const cap = insuranceSum * CAP_MULTIPLIER;
112	  const totalPayout = damages.reduce((sum, damage) => sum + (damage.amount - DEDUCTIBLE), 0);
113	  return { payout: totalPayout, remainingCap: cap - totalPayout };
114	}
