116	export function processScenario(scenario: {
117	  customer: { yearsWithMHPCO: number };
118	  steps: Array<{
119	    op: string;
120	    items?: Array<{ type: string; cursed?: boolean; enchantment?: number }>;
121	    policy?: number;
122	    incident?: { cause: string; damages: Array<{ type: string; amount: number }> };
123	  }>;
124	}): ScenarioOutcome {
125	  const results: Array<QuoteResult | ClaimResult> = [];
126	  const policies: Array<{ items: Array<{ type: string; cursed?: boolean; enchantment?: number }> }> = [];
127	  let quoteIndex = 0;
128	
129	  for (const step of scenario.steps) {
130	    if (step.op === "claim") {
131	      results.push(calculateClaimResult(policies[step.policy!], step.incident!.damages));
132	    } else {
133	      const items = step.items ?? [];
134	      policies.push({ items });
135	      results.push({
136	        premium: calculateQuotePremium(items, scenario.customer.yearsWithMHPCO, quoteIndex),
137	      });
138	      quoteIndex++;
139	    }
140	  }
141	
142	  return { results };
143	}
